class Solution:
    def minimumOperations(self, nums):
        # Independent: literally simulate the described operation.
        a = list(nums)
        ops = 0
        while any(v > 0 for v in a):
            x = min(v for v in a if v > 0)
            a = [v - x if v > 0 else 0 for v in a]
            ops += 1
        return ops

